mapper.select:
    			select file_dir from TB_MED_TEMP_FILE_DIR
    			where  1 = 1

				AND FUNC_ID =  #{funcId}


				AND CAT_ID =  #{catId}

SELECT T1.DISCLAIMER_ID, T1.CONTENT_ID, T1.ITEM_NAME, T1.TITLE, T1.CONTENT FROM TB_MED_DISCLAIMER T1 INNER JOIN (SELECT DISCLAIMER_ID, CONTENT_ID, MAX(START_DATE) AS START_DATE FROM TB_MED_DISCLAIMER WHERE START_DATE <= TO_CHAR(SYSDATE,'YYYYMMDD') AND END_DATE > TO_CHAR(SYSDATE,'YYYYMMDD')
AND DISCLAIMER_ID = #{disclaimerId}
GROUP BY DISCLAIMER_ID, CONTENT_ID ) T2 ON T1.DISCLAIMER_ID = T2.DISCLAIMER_ID AND T1.CONTENT_ID = T2.CONTENT_ID AND T1.START_DATE = T2.START_DATE ORDER BY T1.DISCLAIMER_ID, T1.CONTENT_ID
